class BidirectionalMistralConfig(MistralConfig):
    model_type = BIDIR_MISTRAL_TYPE
    keys_to_ignore_at_inference = ["past_key_values"]

    def __init__(
        self,
        skip_layer_start:Optional[int]=None,
        num_layers_to_skip:Optional[int]=None,
        skip_layer_func:Optional[Callable]=None,
        **kwargs
    ):
        super().__init__(**kwargs)
        self.skip_layer_start = self.skip_layer_end = None
        self.skip_layer_func = skip_layer_func
        
        if skip_layer_start is not None:
            self.skip_layer_start = skip_layer_start - 1
            self.skip_layer_end = min(skip_layer_start + num_layers_to_skip, self.num_hidden_layers)
    
            assert skip_layer_start <= self.num_hidden_layers and skip_layer_start > 0, (
                f"Starting layer to be skipped should be less than {self.num_hidden_layers}."
            )
            

