class NVM009Encoder(NVEmbedModel):
    
    def __init__(
        self, 
        config,
        normalize:Optional[bool]=True,
    ):
        self.normalize = normalize
        super().__init__(config)
        
    @delegates(NVEmbedModel.__call__)
    def forward(
        self, 
        input_ids:Optional[torch.Tensor]=None, 
        attention_mask:Optional[torch.Tensor]=None,
        pool_mask: Optional[torch.Tensor]=None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
        **kwargs
    ):
        outputs = self.embedding_model(
            input_ids=input_ids,
            attention_mask=attention_mask,
            output_attentions=output_attentions,
            output_hidden_states=output_hidden_states,
        )
        embeds = self.latent_attention_model(
            outputs.last_hidden_state,
            # pool_mask,
        )

        pool_mask = attention_mask if pool_mask is None else pool_mask
        embeds = Pooling.mean_pooling(embeds, pool_mask)
        embeds = F.normalize(embeds, dim=1) if self.normalize else embeds
        return outputs, embeds
        

# %% ../../../nbs/34_models.NVM0XX.ipynb 28
class NVM009(NVEmbedModel):
    use_generation,use_representation = False,True
    _tied_weights_keys = ["encoder.embedding_model,encoder.latent_attention_model"]
    
    def __init__(
        self,
        config,
        **kwargs
    ):
        super().__init__(config, **kwargs)
        self.use_encoder_parallel = config.use_encoder_parallel
        self.encoder = NVM009Encoder(config, normalize=config.normalize)
        self.loss_fn = MultiTriplet(margin=config.margin, n_negatives=config.n_negatives, tau=config.tau, 
                                    apply_softmax=config.apply_softmax, reduce='mean')
        self.post_init()
        self.remap_post_init()
        
    def remap_post_init(self):
        self.embedding_model = self.encoder.embedding_model
        self.latent_attention_model = self.encoder.latent_attention_model
    
    def forward(
        self,
        data_input_ids:Optional[torch.Tensor]=None,
        data_attention_mask:Optional[torch.Tensor]=None,
        data_pool_mask:Optional[torch.Tensor]=None,
        lbl2data_data2ptr:Optional[torch.Tensor]=None,
        lbl2data_idx:Optional[torch.Tensor]=None,
        lbl2data_input_ids:Optional[torch.Tensor]=None,
        lbl2data_attention_mask:Optional[torch.Tensor]=None,
        lbl2data_pool_mask:Optional[torch.Tensor]=None,
        plbl2data_data2ptr:Optional[torch.Tensor]=None,
        plbl2data_idx:Optional[torch.Tensor]=None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
        return_dict: Optional[bool] = None,
        **kwargs
    ):
        return_dict = return_dict if return_dict is not None else self.config.use_return_dict
        encoder = nn.DataParallel(module=self.encoder) if self.use_encoder_parallel else self.encoder
        
        data_o, data_repr = encoder(data_input_ids, data_attention_mask, data_pool_mask, output_attentions=output_attentions, 
                                    output_hidden_states=output_hidden_states, return_dict=return_dict)
        
        loss = lbl2data_o = lbl2data_repr = None
        if lbl2data_input_ids is not None:
            lbl2data_o, lbl2data_repr = encoder(lbl2data_input_ids, lbl2data_attention_mask, lbl2data_pool_mask, 
                                                output_attentions=output_attentions, output_hidden_states=output_hidden_states, 
                                                return_dict=return_dict)
            
            loss = self.loss_fn(data_repr, lbl2data_repr, lbl2data_data2ptr, lbl2data_idx, 
                                plbl2data_data2ptr, plbl2data_idx, **kwargs)

        if not return_dict:
            o = (data_repr, lbl2data_repr)
            return ((loss,) + o) if loss is not None else o

        return XCModelOutput(
            loss=loss,
            data_repr=data_repr,
            data_output=data_o,
            lbl2data_repr=lbl2data_repr,
            lbl2data_output=lbl2data_o,
        )
        
